function solve(nums: number[]): number[] {
    const n = nums.length;
    const ans: number[] = new Array(2 * n);

    // Fill the first n elements with nums
    for (let i = 0; i < n; i++) {
        ans[i] = nums[i];
    }

    // Fill the last n elements with the reverse of nums
    for (let i = 0; i < n; i++) {
        // ans[i + n] = nums[n - i - 1]
        ans[i + n] = nums[n - 1 - i];
    }

    return ans;
}
